// modules/auth/routes/password-reset-confirm.ts
import { Request, Response } from 'bun';
import { requireUser, getSession, createSession, invalidateSession } from '../module.contract';
import { Result, ok, err } from '/lib/result';
import { parseBody } from '/lib/validate';
import bcrypt from 'bcrypt';

export async function passwordResetConfirm(req: Request): Promise<Response> {
  const body = await parseBody<{ token: string; newPassword: string }>(req);

  // Validate input
  if (!body.token || !body.newPassword) {
    return err({ code: 'INVALID_INPUT', message: 'Token and new password are required' });
  }

  // Check if the session is valid
  const session = await getSession(req);
  if (!session) {
    return err({ code: 'SESSION_INVALID', message: 'Session is invalid or expired' });
  }

  // Hash the new password
  const hashedPassword = await bcrypt.hash(body.newPassword, 10);

  // Update user's password in the database
  try {
    await query('UPDATE users SET password = $1 WHERE id = $2', [hashedPassword, session.userId]);
  } catch (error) {
    return err({ code: 'DATABASE_ERROR', message: 'Failed to update user password' });
  }

  // Invalidate all existing sessions for the user
  try {
    await invalidateSession(session.userId);
  } catch (error) {
    return err({ code: 'SESSION_INVALIDATE_ERROR', message: 'Failed to invalidate user sessions' });
  }

  // Return success response
  return ok({ message: 'Password reset successful' });
}

